#include<cstdio>
using namespace std;

int main()
{
	int s=0,n=0,x[13],a;
	for(int i=1;i<=12;i++)
	{
		scanf("%d",&x[i]);
	}
	for(int i=1;i<=12;i++)
	{
		n=n+300-x[i];
		if(n<0)
		{
			printf("-");
			printf("%d",i);
			return 0;
		}
	    else
	    {
	    		while(n>=100)
		      {
			     n-=100;
			     s+=100;
		      }
	    }
	}
	a=s/5;
	printf("%d",s+a+n);
	return 0;
}
